export const KAIROS_CSS_SOURCE = String.raw`:root{--kr-blue:#2563eb;--kr-navy:#07111f;--kr-ink:#172033;--kr-muted:#667085;--kr-line:#dfe5ee;--kr-soft:#f5f7fb;--kr-white:#fff;--kr-radius:26px}.mmg-kairos{color:var(--kr-ink);font-family:var(--font-body-family,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif)}.mmg-kairos *{box-sizing:border-box}.mmg-kairos h1,.mmg-kairos h2,.mmg-kairos h3{font-family:var(--font-heading-family,var(--font-body-family,system-ui));letter-spacing:-.04em;color:var(--kr-ink);margin-top:0}.mmg-kairos h1{font-size:clamp(3.7rem,7.5vw,7.2rem);line-height:.94;max-width:10ch;margin-bottom:1.5rem}.mmg-kairos h2{font-size:clamp(2.5rem,5vw,4.7rem);line-height:1.02}.mmg-kairos h3{font-size:clamp(1.35rem,2.2vw,1.9rem);line-height:1.14}.mmg-kairos p{font-size:1.08rem;line-height:1.72;color:var(--kr-muted)}.kairos-shell{width:min(1220px,calc(100% - 48px));margin:auto}.kairos-hero{padding:clamp(5.5rem,9vw,8.5rem) 0;background:radial-gradient(circle at 85% 20%,#dbeafe 0,transparent 34%),linear-gradient(180deg,#fff,#f7f9fc);border-bottom:1px solid var(--kr-line)}.kairos-hero__grid,.kairos-split{display:grid;grid-template-columns:1.1fr .9fr;gap:clamp(3rem,7vw,7rem);align-items:center}.kairos-lead{font-size:clamp(1.3rem,2.4vw,1.8rem)!important;color:var(--kr-ink)!important;max-width:850px}.kairos-eyebrow{display:inline-flex;font-size:.82rem!important;font-weight:850;letter-spacing:.13em;text-transform:uppercase;color:var(--kr-blue)!important;background:#eaf1ff;border-radius:999px;padding:.68rem .95rem}.kairos-actions{display:flex;flex-wrap:wrap;gap:.8rem;margin-top:2rem}.kairos-actions--center{justify-content:center}.kairos-button{display:inline-flex;align-items:center;justify-content:center;min-height:56px;padding:.9rem 1.5rem;border:1px solid var(--kr-line);border-radius:999px;background:#fff;color:var(--kr-ink);font-weight:820;text-decoration:none}.kairos-button--primary{background:var(--kr-blue);border-color:var(--kr-blue);color:#fff}.kairos-console{background:var(--kr-navy);border-radius:32px;padding:2rem;box-shadow:0 28px 80px rgba(7,17,31,.22)}.kairos-console p,.kairos-console strong,.kairos-console div{color:#fff}.kairos-console p{font-size:.8rem;text-transform:uppercase;letter-spacing:.12em;opacity:.65}.kairos-console strong{display:block;font-size:1.55rem;line-height:1.25;margin-bottom:1.4rem}.kairos-console div{display:grid;grid-template-columns:42px 1fr;gap:.8rem;padding:1rem 0;border-top:1px solid rgba(255,255,255,.12)}.kairos-console span{color:#93c5fd;font-weight:850}.kairos-section{padding:clamp(5.5rem,9vw,8.5rem) 0}.kairos-section--soft{background:var(--kr-soft);border-block:1px solid var(--kr-line)}.kairos-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1.2rem;margin-top:3rem}.kairos-grid--four{grid-template-columns:repeat(4,1fr)}.kairos-grid article{background:#fff;border:1px solid var(--kr-line);border-radius:var(--kr-radius);padding:2rem;min-height:290px;display:flex;flex-direction:column}.kairos-grid article>b,.kairos-grid article>span{font-size:.8rem;font-weight:850;letter-spacing:.09em;text-transform:uppercase;color:var(--kr-blue)}.kairos-grid a{margin-top:auto;color:var(--kr-blue);font-weight:820;text-decoration:none}.kairos-section--dark{background:linear-gradient(145deg,#1d4ed8,var(--kr-navy))}.kairos-section--dark h2,.kairos-section--dark p{color:#fff}.kairos-section--dark .kairos-eyebrow{background:rgba(255,255,255,.14);color:#fff!important}.kairos-principles{display:grid;gap:.85rem}.kairos-principles article{background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.16);border-radius:18px;padding:1.2rem}.kairos-principles strong,.kairos-principles span{display:block;color:#fff}.kairos-principles span{font-size:.9rem;margin-top:.25rem;opacity:.76}.kairos-final{text-align:center;padding:clamp(5.5rem,9vw,8.5rem) 0;background:linear-gradient(180deg,#fff,#f7f9fc)}.kairos-final h2,.kairos-final>div>p:not(.kairos-eyebrow){max-width:900px;margin-inline:auto}@media(max-width:980px){.kairos-grid--four{grid-template-columns:repeat(2,1fr)}}@media(max-width:900px){.kairos-hero__grid,.kairos-split{grid-template-columns:1fr}.kairos-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:640px){.kairos-shell{width:min(100% - 28px,1220px)}.kairos-grid,.kairos-grid--four{grid-template-columns:1fr}.mmg-kairos h1{font-size:clamp(3rem,15vw,4.8rem)}.kairos-actions .kairos-button{width:100%}}`;